#include <iostream>
using namespace std;

// 1. Void функція (нічого не повертає, лише виконує дію)
void printGreeting(string title) {
    cout << "======= " << title << " =======" << endl;
}

// 2. Функція, що повертає значення
// Отримує два числа, повертає більше з них
int findMaximum(int a, int b) {
    if (a > b) {
        return a; // Після return функція негайно завершує роботу!
    } else {
        return b;
    }
}

// 3. Звичайна функція обчислення площі кола
double calculateArea(double radius) {
    const double PI = 3.14159;
    return PI * radius * radius;
}

int main() {
    printGreeting("Початок програми");

    int x = 10;
    int y = 25;

    // Виклик функції. Результат зберігається в змінну maxVal
    int maxVal = findMaximum(x, y);
    cout << "Найбільше число: " << maxVal << endl;

    // Можна викликати функцію прямо всередині cout!
    cout << "Площа кола (r=5): " << calculateArea(5.0) << endl;

    printGreeting("Кінець програми");
    return 0;
}
